import{_ as a,o as t,c as o,ae as s}from"./chunks/framework.BGHOrOyn.js";const r="/gitbook-personnal-docs/assets/small%20longfeltwant1.DLUPDGN_.",i="/gitbook-personnal-docs/assets/small%20bitofcoast2.D4z1d8vi.",n="/gitbook-personnal-docs/assets/small%20there%20and%20back%20again1.BZ6OVJqS.",l="/gitbook-personnal-docs/assets/small%20testing%20trips1.DUlk8awW.",h="/gitbook-personnal-docs/assets/small%20ces2010%201.BxkXkA1E.",d="/gitbook-personnal-docs/assets/small%20firststart.Cfy1-b5J.",p="/gitbook-personnal-docs/assets/small%20driving.PM81ho1h.",g="/gitbook-personnal-docs/assets/small%20converter.C5_4PEvi.",c="/gitbook-personnal-docs/assets/small%20convertingcsv.C6rZgKKb.",x=JSON.parse('{"title":"OBD GPS Logger for Linux and OSX","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/obd-gps-logger-for-linux-and-osx.md","filePath":"obd2/obd-gps-logger-for-linux-and-osx.md"}'),u={name:"obd2/obd-gps-logger-for-linux-and-osx.md"};function b(m,e,f,k,y,w){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="obd-gps-logger-for-linux-and-osx" tabindex="-1">OBD GPS Logger for Linux and OSX <a class="header-anchor" href="#obd-gps-logger-for-linux-and-osx" aria-label="Permalink to &quot;OBD GPS Logger for Linux and OSX&quot;">​</a></h1><p>\\ [Modules | Screenshots | Log Output | Supported OSs | Download | Contact ]</p><p>It does exactly what it says on the tin. It logs OBDII and GPS data on Linux, OSX and others.</p><p>It can then take that logged data, and write useful output formats</p><p>If you find obdgpslogger useful, please don&#39;t hesitate to drop me an email at <a href="mailto:chunky@icculus.org" target="_blank" rel="noreferrer">chunky@icculus.org</a> and let me know of any success, failures, or questions you might have!</p><h2 id="modules" tabindex="-1">Modules <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;Modules&quot;">​</a></h2><p>OBD GPS Logger comes as a bunch of small tools, each intended to complete a single task. I list these modules on a page of their own.</p><p>Of specific mention is an OBD II Simulator, which has been given its own page to explore some of its features.</p><p>Each module intended for end users has a manpage in the distribution. A simple text version of the manpages can be found here: <a href="./../.gitbook/assets/manpages (1).html">manpages</a></p><h3 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h3><h4 id="samples-and-google-earth" tabindex="-1">Samples and Google Earth <a class="header-anchor" href="#samples-and-google-earth" aria-label="Permalink to &quot;Samples and Google Earth&quot;">​</a></h4><p>This is what the output looks like when loaded in Google Earth</p><p>Click each screenshot below to take you to a page with higher resolution images, the logs, and the final output files.</p><table tabindex="0"><thead><tr><th>Cross-country road trip</th><th><a href="./../.gitbook/assets/longfeltwant.html"><img src="'+r+'" alt=""></a></th><th>Bit of Coast</th><th><a href="./../.gitbook/assets/bitofcoast.html"><img src="'+i+'" alt=""></a></th></tr></thead><tbody><tr><td>There and Back Again</td><td><a href="./../.gitbook/assets/there and back again (1).html"><img src="'+n+'" alt=""></a></td><td>Testing Trips</td><td><a href="./../.gitbook/assets/testingtrips.html"><img src="'+l+'" alt=""></a></td></tr><tr><td>Vegas trip for CES 2010</td><td><a href="./../.gitbook/assets/ces2010 (1).html"><img src="'+h+'" alt=""></a></td><td></td><td></td></tr></tbody></table><h4 id="gui" tabindex="-1">GUI <a class="header-anchor" href="#gui" aria-label="Permalink to &quot;GUI&quot;">​</a></h4><p>obdgpslogger is actually a small group of command-line applications, and a UI that can be used to launch them. The UI is entirely optional, and the full capabilities of obdgpslogger are available without any graphical systems even running.</p><p>Here are some screenshots of it.</p><table tabindex="0"><thead><tr><th>When you first start the UI...</th><th><a href="./../.gitbook/assets/firststart (1).html"><img src="'+d+'" alt=""></a></th><th>While Driving...</th><th><a href="./../.gitbook/assets/driving (1).html"><img src="'+p+'" alt=""></a></th></tr></thead><tbody><tr><td>Click &quot;Convert log to...&quot;</td><td><a href="./../.gitbook/assets/converter.html"><img src="'+g+'" alt=""></a></td><td>While converting the log...</td><td><a href="./../.gitbook/assets/convertingcsv.html"><img src="'+c+`" alt=""></a></td></tr></tbody></table><h3 id="what-does-it-do" tabindex="-1">What does it do? <a class="header-anchor" href="#what-does-it-do" aria-label="Permalink to &quot;What does it do?&quot;">​</a></h3><p>Your car has lots of interesting things it can tell you from its on-board computer while it&#39;s running. Things like how fast you&#39;re going, how fast the engine&#39;s going, the air flow into the engine, the throttle position... everything. If you want to know more, <a href="http://www.google.com/search?q=obdII" target="_blank" rel="noreferrer">google obdII</a>, and enjoy the rabbit hole.</p><p>As with so many open-source projects, this is scratching an itch: There&#39;s a severe lack of applications that run on OSX or Linux that can log OBDII data.</p><p>My gem-of-an-idea from the outset was to be able to log this stuff as I was driving, along with GPS position, and later on plot an overlay on a map of where you drove, and how efficiently the car was running at each instant</p><h3 id="what-do-i-need" tabindex="-1">What do I need? <a class="header-anchor" href="#what-do-i-need" aria-label="Permalink to &quot;What do I need?&quot;">​</a></h3><p>The core interest in this application is OBDII. To log from OBDII, you&#39;ll need an elm327-compatible device [ie, &quot;all of them&quot;] plugged into your laptop and presenting itself as a serial port device. Just about anything you can find on the internet that says &quot;elm327&quot; and has a plug that fits a hole on your laptop should work.</p><p>I have all these three devices. I use the OBDLink the most [it&#39;s the fastest at sampling, and has the most powerful set of power-saving settings], followed by the OBDPros. I rarely use the OBDKey anymore:</p><ul><li><a href="http://www.scantool.net/obdlink.html" target="_blank" rel="noreferrer">OBDLink device</a></li><li><a href="http://www.obdpros.com/product_info.php?products_id=133" target="_blank" rel="noreferrer">OBDPros USB</a></li><li><a href="http://www.obdkey.com/" target="_blank" rel="noreferrer">Bluetooth OBDKey</a></li></ul><p>If you want to use the GPS logging part, you&#39;ll need a <a href="http://gpsd.berlios.de/hardware.html" target="_blank" rel="noreferrer">GPS receiver compatible with gpsd</a>, and gpsd. For bluetooth, I&#39;m using one of these: <a href="http://www.amazon.com/gp/product/B000GWGHOK" target="_blank" rel="noreferrer">Globalsat BT-359</a> and am very happy with it. In general, though, I prefer the <a href="http://store.mp3car.com/BU_353_USB_GPS_Receiver_p/gps-002.htm" target="_blank" rel="noreferrer">BU-353</a> since you don&#39;t have to deal with batteries or turning on and enabling gpsd. [yay hotplug]</p><h3 id="can-it-hurt-my-car" tabindex="-1">Can it hurt my car? <a class="header-anchor" href="#can-it-hurt-my-car" aria-label="Permalink to &quot;Can it hurt my car?&quot;">​</a></h3><p>No.</p><p>OBDII is purely a way to get diagnostic information from the car. The only thing that could be classed as &quot;writing&quot; to the car&#39;s computer through the OBDII port is clearing diagnostic codes - which the engine dutifully sets again if whatever-was-wrong is still wrong.</p><h3 id="what-do-i-do-with-my-logs" tabindex="-1">What do I do with my &quot;logs&quot;? <a class="header-anchor" href="#what-do-i-do-with-my-logs" aria-label="Permalink to &quot;What do I do with my &quot;logs&quot;?&quot;">​</a></h3><h4 id="google-earth" tabindex="-1">Google Earth <a class="header-anchor" href="#google-earth" aria-label="Permalink to &quot;Google Earth&quot;">​</a></h4><p>Included in the distribution is a program called obd2kml. This reads the database generated by obdlogger and exports to a Google Earth .kml file</p><h4 id="spreadsheet-export" tabindex="-1">Spreadsheet export <a class="header-anchor" href="#spreadsheet-export" aria-label="Permalink to &quot;Spreadsheet export&quot;">​</a></h4><p>Included in the distribution is a program called obd2csv. This reads the database generated by obdogger and exports it to a CSV file with a couple extra useful columns pre-calculated.</p><p>Then open obdlogger.csv in your favorite spreadsheet to use as you please.</p><h4 id="gpx-export" tabindex="-1">GPX export <a class="header-anchor" href="#gpx-export" aria-label="Permalink to &quot;GPX export&quot;">​</a></h4><p>GPX is a standard format for GPS data. You can upload it to <a href="http://openstreetmap.org/" target="_blank" rel="noreferrer">openstreetmap</a> among others, and many tools recognise it.</p><h3 id="supported-operating-systems" tabindex="-1">Supported Operating Systems <a class="header-anchor" href="#supported-operating-systems" aria-label="Permalink to &quot;Supported Operating Systems&quot;">​</a></h3><p>Short Version: OSX, Linux, cygwin on Windows</p><p>Long Version: I&#39;m doing most development and testing on OSX, but it&#39;s fully POSIX-compliant. Which means it works on OSX, Linux, Solaris. If you use windows, it works with cygwin [see below]</p><p>Longer, opaque version: I have run it on ARM Linux, x86 Linux, x86_64 Linux, PPC Linux, PPC OSX 10.4, Intel OSX 10.4 and 10.5, various flavors of Cygwin. Most modules work under MSYS, except the logger itself.</p><h3 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h3><h4 id="typical-doc-type-things" tabindex="-1">Typical doc type things <a class="header-anchor" href="#typical-doc-type-things" aria-label="Permalink to &quot;Typical doc type things&quot;">​</a></h4><p>Some links to typical documents [direct links to svn versions]:</p><ul><li><a href="http://svn.icculus.org/obdgpslogger/trunk/README?view=markup" target="_blank" rel="noreferrer">README</a></li><li><a href="http://svn.icculus.org/obdgpslogger/trunk/ChangeLog?view=markup" target="_blank" rel="noreferrer">ChangeLog</a></li><li><a href="http://svn.icculus.org/obdgpslogger/trunk/TODO?view=markup" target="_blank" rel="noreferrer">TODO</a></li><li><a href="http://svn.icculus.org/obdgpslogger/trunk/COPYING?view=markup" target="_blank" rel="noreferrer">COPYING</a>. The license is GPLv2+.</li></ul><h4 id="distribution-packages" tabindex="-1">Distribution Packages <a class="header-anchor" href="#distribution-packages" aria-label="Permalink to &quot;Distribution Packages&quot;">​</a></h4><p>Packaging stuff for various distros is in svn://svn.icculus.org/obdgpslogger/branches/packaging</p><p>At time of writing, packages are available through your distribution if you&#39;re running Debian Sid or Testing [will be in Wheezy], Ubuntu Oneiric, or Arch AUR.</p><p>OpenSolaris spec files are in the svn packaging, but Oracle have killed Jucr so I no longer have an easy install path for end users.</p><p>Packaging is in progress, but not yet official, for <a href="https://bugzilla.redhat.com/show_bug.cgi?id=709125" target="_blank" rel="noreferrer">Fedora</a>, <a href="https://build.opensuse.org/package/binaries?package=obdgpslogger&amp;project=home%3Arandybb%3Atesting&amp;repository=openSUSE_11.4" target="_blank" rel="noreferrer">OpenSuSE</a>, and Meego. That may have changed by the time you read this.</p><h4 id="tarball" tabindex="-1">Tarball <a class="header-anchor" href="#tarball" aria-label="Permalink to &quot;Tarball&quot;">​</a></h4><p>The current version is downloadable as source here: <a href="./../.gitbook/assets/obdgpslogger 0.16 (1).tar.html">obdgpslogger-0.16.tar.gz</a></p><h4 id="mac-users" tabindex="-1">Mac Users <a class="header-anchor" href="#mac-users" aria-label="Permalink to &quot;Mac Users&quot;">​</a></h4><p>There&#39;s a macintel bundle, with included gpsd, here: <a href="./../.gitbook/assets/OBDGPSLogger 0 (1).11 Darwin.html">OBDGPSLogger-0.11-Darwin.dmg</a></p><h4 id="subversion-checkout" tabindex="-1">Subversion Checkout <a class="header-anchor" href="#subversion-checkout" aria-label="Permalink to &quot;Subversion Checkout&quot;">​</a></h4><p>This is probably more recent than the numbered tarball above, but may have issues</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">svn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> co</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svn://svn.icculus.org/obdgpslogger/trunk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obdgpslogger</span></span></code></pre></div><p>You can browse the svn repo here: <a href="http://svn.icculus.org/obdgpslogger/" target="_blank" rel="noreferrer">http://svn.icculus.org/obdgpslogger/</a></p><h4 id="building" tabindex="-1">Building <a class="header-anchor" href="#building" aria-label="Permalink to &quot;Building&quot;">​</a></h4><p>I strongly suggest installing gpsd first.</p><p>Build it using cmake:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # or ccmake to edit options</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # optional</span></span></code></pre></div><p>Binaries are placed in the &quot;bin&quot; dir of your top level source directory. If you want to install to a different prefix, change CMAKE_INSTALL_PREFIX when you run ccmake</p><h4 id="building-on-windows" tabindex="-1">Building on Windows <a class="header-anchor" href="#building-on-windows" aria-label="Permalink to &quot;Building on Windows&quot;">​</a></h4><p>On Windows, the software works with <a href="http://www.cygwin.com/" target="_blank" rel="noreferrer">cygwin</a>. [obdsim also works with msys/mingw]</p><p>You need the following packages [install them through cygwin&#39;s setup.exe, selecting some of them may select others automatically, you should leave those ones on]:</p><ul><li>devel/cmake</li><li>devel/gcc</li><li>devel/make</li><li>devel/subversion</li></ul><p>Open Cygwin from the desktop or start menu entry, and then run the same commands as &quot;building&quot; above</p><h3 id="mailing-list-and-forum" tabindex="-1">Mailing List and Forum <a class="header-anchor" href="#mailing-list-and-forum" aria-label="Permalink to &quot;Mailing List and Forum&quot;">​</a></h3><p>OBD GPS Logger has a mailing list. Subscribe to it by visiting the icculus.org mailman page for it: <a href="http://icculus.org/mailman/listinfo/obdgpslogger" target="_blank" rel="noreferrer">http://icculus.org/mailman/listinfo/obdgpslogger</a></p><p>mp3car have provided me some forum space for this project here: <a href="http://www.mp3car.com/vbulletin/obdii-gps-logger/" target="_blank" rel="noreferrer">http://www.mp3car.com/vbulletin/obdii-gps-logger/</a></p><p><a href="mailto:chunky@icculus.org" target="_blank" rel="noreferrer">Gary (-;<br> &lt;chunky@icculus.org&gt;</a></p><br>`,74)])])}const _=a(u,[["render",b]]);export{x as __pageData,_ as default};
